output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?name ?nameLabel(COUNT(?person) AS ?count) WHERE {
  ?person wdt:P31 wd:Q5 ; wdt:P19 ?birthPlace ; wdt:P735 ?name .
  ?birthPlace wdt:P17 wd:Q145 .
  ?name wdt:P31 wd:Q11879590 . MINUS {
    wd:Q50049 wdt:P674 ?character .
    ?character wdt:P735 ?name .
  }
  OPTIONAL {
    ?name rdfs:label ?nameLabel .
    FILTER(LANG(?nameLabel) = "en")
  }
}
GROUP BY ?name ?nameLabel
ORDER BY DESC(?count)
LIMIT 10

